  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { BreadcrumbItem, Text, TextVariants } from '@patternfly/react-core';
  4	import { Link, useNavigate, useParams } from 'react-router-dom-v5-compat';
  5	import {
  6	  getGroupVersionKindForModel,
  7	  useAccessReview,
  8	  useAnnotationsModal,
  9	  useDeleteModal,
 10	  useK8sWatchResource,
 11	  useLabelsModal,
 12	} from '@openshift-console/dynamic-plugin-sdk';
 13	import TaskDetails from './TaskDetails';
 14	import DetailsPage from '../details-page/DetailsPage';
 15	import { navFactory } from '../utils/horizontal-nav';
 16	import { TaskModel } from '../../models';
 17	import { TaskKind } from '../../types';
 18	import { getReferenceForModel } from '../pipelines-overview/utils';
 19	import { getTaskName } from '../utils/pipeline-augment';
 20	import { ErrorPage404 } from '../common/error';
 21	import { LoadingBox } from '../status/status-box';
 22	import ResourceYAMLEditorTab from '../yaml-editor/ResourceYAMLEditorTab';
 23	
 24	type TaskDetailsPageProps = {
 25	  name: string;
 26	  namespace: string;
 27	};
 28	
 29	const TaskDetailsPage: React.FC<TaskDetailsPageProps> = () => {
 30	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 31	  const params = useParams();
 32	  const navigate = useNavigate();
 33	  const { name, ns: namespace } = params;
 34	  const [task, loaded, loadError] = useK8sWatchResource<TaskKind>({
 35	    groupVersionKind: getGroupVersionKindForModel(TaskModel),
 36	    namespace,
 37	    name,
 38	  });
 39	  const launchAnnotationsModal = useAnnotationsModal(task);
 40	  const launchLabelsModal = useLabelsModal(task);
 41	  const launchDeleteModal = useDeleteModal(task);
 42	  const canEditResource = useAccessReview({
 43	    group: TaskModel.apiGroup,
 44	    resource: TaskModel.plural,
 45	    verb: 'update',
 46	    name,
 47	    namespace,
 48	  });
 49	  const canDeleteResource = useAccessReview({
 50	    group: TaskModel.apiGroup,
 51	    resource: TaskModel.plural,
 52	    verb: 'delete',
 53	    name,
 54	    namespace,
 55	  });
 56	
 57	  const editURL = `/k8s/ns/${namespace}/${getReferenceForModel(
 58	    TaskModel,
 59	  )}/${encodeURIComponent(name)}/yaml`;
 60	
 61	  const resourceTitleFunc = React.useMemo(() => {
 62	    return <div className="task-details-page">{getTaskName(task)} </div>;
 63	  }, [task]);
 64	
 65	  if (!loaded) {
 66	    return loadError ? <ErrorPage404 /> : <LoadingBox />;
 67	  }
 68	
 69	  return (
 70	    <DetailsPage
 71	      obj={task}
 72	      model={TaskModel}
 73	      title={<Text component={TextVariants.h1}>{resourceTitleFunc}</Text>}
 74	      actions={[
 75	        {
 76	          key: 'edit-labels',
 77	          label: t('Edit labels'),
 78	          onClick: () => launchLabelsModal(),
 79	          disabled: !canEditResource[0],
 80	        },
 81	        {
 82	          key: 'edit-annotations',
 83	          label: t('Edit annotations'),
 84	          onClick: () => launchAnnotationsModal(),
 85	          disabled: !canEditResource[0],
 86	        },
 87	        {
 88	          key: 'edit-task',
 89	          label: t('Edit {{resourceKind}}', {
 90	            resourceKind: TaskModel.kind,
 91	          }),
 92	          onClick: () => navigate(editURL),
 93	          disabled: !canEditResource[0],
 94	        },
 95	        {
 96	          key: 'delete-task',
 97	          label: t('Delete {{resourceKind}}', {
 98	            resourceKind: TaskModel.kind,
 99	          }),
100	          onClick: () => launchDeleteModal(),
101	          disabled: !canDeleteResource[0],
102	        },
103	      ]}
104	      pages={[
105	        navFactory.details(TaskDetails),
106	        navFactory.editYaml(ResourceYAMLEditorTab),
107	      ]}
108	      breadcrumbs={[
109	        <BreadcrumbItem key="app-link" component="div">
110	          <Link
111	            data-test="breadcrumb-link"
112	            className="pf-v6-c-breadcrumb__link"
113	            to={`/tasks/ns/${namespace}/`}
114	          >
115	            {t('Tasks')}
116	          </Link>
117	        </BreadcrumbItem>,
118	        {
119	          path: `/tasks/ns/${namespace}/`,
120	          name: t('Task details'),
121	        },
122	      ]}
123	    />
124	  );
125	};
126	
127	export default TaskDetailsPage;

